930‚Üí    {
931‚Üí        var advised = FiveCardDrawEngine.ComputeAdvisedHolds(hand);
932‚Üí        var advisedSet = advised.ToHashSet();
933‚Üí        var actualSet = holdIndexes.Where(i => i >= 0 && i < 5).ToHashSet();
934‚Üí        var evaluation = FiveCardDrawEngine.EvaluateHand(hand);
935‚Üí        var delta = advisedSet.Except(actualSet).Count() + actualSet.Except(advisedSet).Count();
936‚Üí
937‚Üí        if (evaluation.Category is HandCategory.FourOfAKind or HandCategory.FullHouse or HandCategory.Flush or HandCategory.Straight)
938‚Üí        {
939‚Üí            if (delta > 0) return 3;
940‚Üí        }
941‚Üí        if (evaluation.Category == HandCategory.ThreeOfAKind && actualSet.Count < 3)
942‚Üí        {
943‚Üí            return 2;
944‚Üí        }
945‚Üí        if (delta >= 4) return 2;
946‚Üí        if (delta >= 2) return 1;
947‚Üí        return -1;
